import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.CNG7EpJN.js";const u=JSON.parse('{"title":"予約・テイクアウト実装リファレンス","description":"","frontmatter":{"title":"予約・テイクアウト実装リファレンス"},"headers":[],"relativePath":"internal/14-reservation-takeout-ops.md","filePath":"internal/14-reservation-takeout-ops.md"}'),r={name:"internal/14-reservation-takeout-ops.md"};function c(i,e,l,s,p,n){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="予約・テイクアウト実装リファレンス" tabindex="-1">予約・テイクアウト実装リファレンス <a class="header-anchor" href="#予約・テイクアウト実装リファレンス" aria-label="Permalink to &quot;予約・テイクアウト実装リファレンス&quot;">​</a></h1><p>この章は、社内向けの実装確認用リファレンスです。2026-04-30 時点の擬似本番環境コードを確認して記述しています。</p><p>お客様向けの説明は、次の章に分けています。</p><ul><li>テイクアウト: <code>/tenant/09-takeout</code></li><li>予約管理: <code>/tenant/24-reservations</code></li></ul><h2 id="対象範囲" tabindex="-1">対象範囲 <a class="header-anchor" href="#対象範囲" aria-label="Permalink to &quot;対象範囲&quot;">​</a></h2><table tabindex="0"><thead><tr><th>領域</th><th>顧客向け画面</th><th>店舗向け画面</th><th>主なAPI</th></tr></thead><tbody><tr><td>テイクアウト</td><td><code>public/customer/takeout.html</code></td><td>管理画面のテイクアウト管理</td><td><code>api/customer/takeout-orders.php</code>, <code>api/store/takeout-management.php</code></td></tr><tr><td>予約</td><td><code>public/customer/reserve.html</code>, <code>public/customer/reserve-detail.html</code></td><td>管理画面の予約ボード</td><td><code>api/customer/reservation-create.php</code>, <code>api/customer/reservation-update.php</code>, <code>api/customer/reservation-cancel.php</code>, <code>api/store/reservations.php</code></td></tr></tbody></table><p>この章では、実装済みの挙動だけを記載します。SMS、LINE、予約金、キャンセル待ちなどは領域ごとに実装範囲が異なるため、混同しないでください。</p><h2 id="テイクアウト実装" tabindex="-1">テイクアウト実装 <a class="header-anchor" href="#テイクアウト実装" aria-label="Permalink to &quot;テイクアウト実装&quot;">​</a></h2><h3 id="構成ファイル" tabindex="-1">構成ファイル <a class="header-anchor" href="#構成ファイル" aria-label="Permalink to &quot;構成ファイル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>種別</th><th>ファイル</th></tr></thead><tbody><tr><td>顧客向けHTML</td><td><code>public/customer/takeout.html</code></td></tr><tr><td>顧客向けJS</td><td><code>public/customer/js/takeout-app.js</code></td></tr><tr><td>顧客向けAPI</td><td><code>api/customer/takeout-orders.php</code></td></tr><tr><td>店舗向けAPI</td><td><code>api/store/takeout-management.php</code></td></tr><tr><td>店舗向けJS</td><td><code>public/admin/js/takeout-manager.js</code></td></tr><tr><td>店舗設定API</td><td><code>api/store/settings.php</code></td></tr><tr><td>店舗設定JS</td><td><code>public/admin/js/settings-editor.js</code></td></tr><tr><td>主なマイグレーション</td><td><code>sql/migration-l1-takeout.sql</code>, <code>sql/migration-p1-65-takeout-operations.sql</code>, <code>sql/migration-p1-66-takeout-customer-convenience.sql</code>, <code>sql/migration-l17-3a-takeout-line-links.sql</code></td></tr></tbody></table><h3 id="顧客向け注文フロー" tabindex="-1">顧客向け注文フロー <a class="header-anchor" href="#顧客向け注文フロー" aria-label="Permalink to &quot;顧客向け注文フロー&quot;">​</a></h3><p>顧客向けテイクアウトは <code>public/customer/js/takeout-app.js</code> が制御します。画面ステップは、商品選択、顧客情報入力、支払い、確認、完了です。</p><p><code>api/customer/takeout-orders.php</code> の主なGETアクションは次の通りです。</p><table tabindex="0"><thead><tr><th>action</th><th>内容</th></tr></thead><tbody><tr><td><code>settings</code></td><td>テイクアウト有効状態、受付時間、準備時間、枠上限、ピーク上限、オンライン決済可否などを返す</td></tr><tr><td><code>slots</code></td><td>指定日の15分単位受取枠を返す</td></tr><tr><td><code>reorder_suggestions</code></td><td>同じ店舗・電話番号の過去注文から再注文候補を返す</td></tr><tr><td><code>status</code></td><td>注文詳細、運用状態、通知状態、到着連絡状態を返す</td></tr></tbody></table><p>POST は通常注文作成と <code>action:&quot;arrival&quot;</code> の到着連絡に対応しています。</p><p>顧客向け注文作成では、現在 <code>payment_method</code> は <code>online</code> のみ受け付けます。商品価格はリクエスト値を信用せず、サーバー側で現在のメニューから再計算します。オンライン決済は、店舗の Stripe Connect または直接 Stripe 設定が利用可能な場合に作成されます。</p><h3 id="受取枠と競合防止" tabindex="-1">受取枠と競合防止 <a class="header-anchor" href="#受取枠と競合防止" aria-label="Permalink to &quot;受取枠と競合防止&quot;">​</a></h3><p>受取枠は15分単位で生成されます。判定に使う主な値は次の通りです。</p><table tabindex="0"><thead><tr><th>値</th><th>参照元</th></tr></thead><tbody><tr><td>受付開始・終了</td><td><code>store_settings.takeout_available_from</code>, <code>takeout_available_to</code></td></tr><tr><td>最短準備時間</td><td><code>takeout_min_prep_minutes</code></td></tr><tr><td>追加待ち時間</td><td><code>takeout_acceptance_delay_minutes</code></td></tr><tr><td>枠あたり注文数</td><td><code>takeout_slot_capacity</code></td></tr><tr><td>枠あたり品数</td><td><code>takeout_slot_item_capacity</code></td></tr><tr><td>ピーク時間帯</td><td><code>takeout_peak_start_time</code>, <code>takeout_peak_end_time</code></td></tr><tr><td>ピーク上限</td><td><code>takeout_peak_slot_capacity</code>, <code>takeout_peak_slot_item_capacity</code></td></tr></tbody></table><p>注文作成時はトランザクション内で同じ店舗・同じ受取日時の注文を <code>FOR UPDATE</code> でロックし、注文数と品数を再確認します。対象外になるステータスは <code>cancelled</code> と <code>paid</code> です。</p><h3 id="再注文候補" tabindex="-1">再注文候補 <a class="header-anchor" href="#再注文候補" aria-label="Permalink to &quot;再注文候補&quot;">​</a></h3><p><code>reorder_suggestions</code> は、店舗IDと電話番号で過去注文を検索します。電話番号は数字のみで10桁または11桁が必要です。</p><p>候補になる注文ステータスは <code>ready</code>, <code>served</code>, <code>paid</code> です。運用ステータスが <code>cancelled</code> または <code>refunded</code> の注文は、該当カラムが存在する環境では候補から除外されます。</p><p>フロントでは、再注文時に現在のメニューに存在し、売り切れではない商品だけをカートへ戻します。</p><h3 id="店舗側テイクアウト管理" tabindex="-1">店舗側テイクアウト管理 <a class="header-anchor" href="#店舗側テイクアウト管理" aria-label="Permalink to &quot;店舗側テイクアウト管理&quot;">​</a></h3><p>店舗向けAPI <code>api/store/takeout-management.php</code> は、認証済みスタッフ以上を前提に、店舗アクセス権を確認して処理します。</p><p>GET は、指定日・店舗・ステータスで <code>order_type=&#39;takeout&#39;</code> の注文を返します。集計項目は次の通りです。</p><table tabindex="0"><thead><tr><th>集計</th><th>判定</th></tr></thead><tbody><tr><td><code>total</code></td><td>対象日のテイクアウト注文数</td></tr><tr><td><code>sla_risk</code></td><td>受取予定時刻が近い未完了注文</td></tr><tr><td><code>sla_late</code></td><td>受取予定時刻を過ぎた未完了注文</td></tr><tr><td><code>packing_incomplete</code></td><td>梱包チェックが完了していない注文</td></tr><tr><td><code>notify_failed</code></td><td>準備完了通知が失敗した注文</td></tr><tr><td><code>refund_attention</code></td><td>キャンセル・返金対応が必要な注文</td></tr><tr><td><code>arrived_waiting</code></td><td>到着連絡があり、まだ受渡済みでない注文</td></tr></tbody></table><p>SLA警告の閾値は <code>store_settings.takeout_sla_warning_minutes</code> です。初期値は10分です。</p><h3 id="店舗側ステータス操作" tabindex="-1">店舗側ステータス操作 <a class="header-anchor" href="#店舗側ステータス操作" aria-label="Permalink to &quot;店舗側ステータス操作&quot;">​</a></h3><p><code>PATCH action:&quot;status&quot;</code> で許可される主な遷移は次の通りです。</p><table tabindex="0"><thead><tr><th>現在</th><th>次</th></tr></thead><tbody><tr><td><code>pending_payment</code></td><td><code>pending</code>, <code>cancelled</code></td></tr><tr><td><code>pending</code></td><td><code>preparing</code></td></tr><tr><td><code>preparing</code></td><td><code>ready</code></td></tr><tr><td><code>ready</code></td><td><code>served</code></td></tr></tbody></table><p><code>ready</code> に更新すると <code>takeout_send_ready_notification</code> が呼ばれ、LINE準備完了通知が試行されます。結果は <code>takeout_ready_notification_status</code> とエラー情報に残ります。</p><h3 id="梱包チェック" tabindex="-1">梱包チェック <a class="header-anchor" href="#梱包チェック" aria-label="Permalink to &quot;梱包チェック&quot;">​</a></h3><p><code>PATCH action:&quot;pack&quot;</code> で保存するチェック項目は固定です。</p><ul><li><code>items</code></li><li><code>chopsticks</code></li><li><code>bag</code></li><li><code>sauce</code></li><li><code>receipt</code></li></ul><p>全項目が true の場合、梱包完了時刻と確認者が保存されます。</p><h3 id="到着連絡" tabindex="-1">到着連絡 <a class="header-anchor" href="#到着連絡" aria-label="Permalink to &quot;到着連絡&quot;">​</a></h3><p>顧客向けAPIの <code>action:&quot;arrival&quot;</code> は、注文ID、店舗ID、電話番号、到着種別、任意メモを受け取ります。</p><p>到着種別は <code>counter</code> と <code>curbside</code> です。キャンセル済み、受渡済み、会計済みの注文には到着連絡できません。</p><h3 id="運用ステータス" tabindex="-1">運用ステータス <a class="header-anchor" href="#運用ステータス" aria-label="Permalink to &quot;運用ステータス&quot;">​</a></h3><p><code>PATCH action:&quot;ops&quot;</code> で保存できる運用ステータスは次の通りです。</p><ul><li><code>normal</code></li><li><code>late_risk</code></li><li><code>late</code></li><li><code>customer_delayed</code></li><li><code>cancel_requested</code></li><li><code>cancelled</code></li><li><code>refund_pending</code></li><li><code>refunded</code></li></ul><p><code>cancelled</code> にした場合、注文が <code>served</code> または <code>paid</code> でなければ注文ステータスも <code>cancelled</code> に更新されます。返金処理そのものは決済事業者側の状態確認が必要です。</p><h3 id="オンライン決済返金との連動" tabindex="-1">オンライン決済返金との連動 <a class="header-anchor" href="#オンライン決済返金との連動" aria-label="Permalink to &quot;オンライン決済返金との連動&quot;">​</a></h3><p><code>api/store/refund-payment.php</code> は、返金対象の <code>payments.order_ids</code> を読み取り、<code>store_id</code> と <code>order_type=&#39;takeout&#39;</code> で再絞り込みした上で、対象注文の <code>takeout_ops_status</code> を <code>refunded</code> に更新します。あわせて <code>takeout_ops_note</code>, <code>takeout_ops_updated_at</code>, <code>takeout_ops_updated_by_user_id</code> も更新します。</p><p>この連動は、テイクアウト運用ボードに「返金済み」を反映するためのものです。決済事業者側の返金処理そのものを代替するものではありません。</p><h3 id="テイクアウト通知の範囲" tabindex="-1">テイクアウト通知の範囲 <a class="header-anchor" href="#テイクアウト通知の範囲" aria-label="Permalink to &quot;テイクアウト通知の範囲&quot;">​</a></h3><p>テイクアウトの準備完了通知は LINE 連携を使います。LINE設定と顧客のLINE紐付けがない場合は送信されません。</p><p>テイクアウトについては、現時点でSMS通知は標準実装されていません。SMS実装済みなのは予約通知側の Webhook 連携です。</p><h2 id="予約実装" tabindex="-1">予約実装 <a class="header-anchor" href="#予約実装" aria-label="Permalink to &quot;予約実装&quot;">​</a></h2><h3 id="構成ファイル-1" tabindex="-1">構成ファイル <a class="header-anchor" href="#構成ファイル-1" aria-label="Permalink to &quot;構成ファイル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>種別</th><th>ファイル</th></tr></thead><tbody><tr><td>顧客向け予約画面</td><td><code>public/customer/reserve.html</code></td></tr><tr><td>顧客向け予約詳細</td><td><code>public/customer/reserve-detail.html</code></td></tr><tr><td>顧客向けJS</td><td><code>public/customer/js/reserve-app.js</code>, <code>public/customer/js/reserve-detail-app.js</code></td></tr><tr><td>顧客向けAPI</td><td><code>api/customer/reservation-create.php</code>, <code>api/customer/reservation-update.php</code>, <code>api/customer/reservation-cancel.php</code>, <code>api/customer/reservation-detail.php</code>, <code>api/customer/reservation-availability.php</code></td></tr><tr><td>店舗向けAPI</td><td><code>api/store/reservations.php</code>, <code>api/store/reservation-settings.php</code>, <code>api/store/reservation-no-show.php</code>, <code>api/store/reservation-seat.php</code>, <code>api/store/reservation-notify.php</code></td></tr><tr><td>店舗向けJS</td><td><code>public/admin/js/reservation-board.js</code></td></tr><tr><td>共通ライブラリ</td><td><code>api/lib/reservation-availability.php</code>, <code>api/lib/reservation-notifier.php</code>, <code>api/lib/reservation-history.php</code>, <code>api/lib/reservation-waitlist.php</code>, <code>api/lib/reservation-risk.php</code>, <code>api/lib/reservation-deposit.php</code></td></tr><tr><td>主なマイグレーション</td><td><code>sql/migration-l9-reservations.sql</code>, <code>sql/migration-rsv-p1-2-waitlist.sql</code>, <code>sql/migration-s3-reservation-uniq.sql</code>, <code>sql/migration-p1-61-reservation-arrival-followups.sql</code>, <code>sql/migration-p1-62-reservation-waitlist-calls.sql</code>, <code>sql/migration-p1-63-reservation-operational-safety.sql</code>, <code>sql/migration-p1-64-reservation-autonomy.sql</code></td></tr></tbody></table><h3 id="web予約作成" tabindex="-1">Web予約作成 <a class="header-anchor" href="#web予約作成" aria-label="Permalink to &quot;Web予約作成&quot;">​</a></h3><p><code>api/customer/reservation-create.php</code> は、IP単位のレート制限を行った上で、店舗のWeb予約設定、入力値、空席、ブラックリスト、高リスク予約金を確認します。</p><p>主な処理は次の通りです。</p><ol><li>店舗が有効か確認します。</li><li><code>online_enabled</code> が有効か確認します。</li><li>名前、電話番号、メール、人数、日時を検証します。</li><li>リードタイム、最大受付日数、人数範囲を確認します。</li><li>ブラックリスト対象の電話番号を拒否します。</li><li><code>compute_slot_availability</code> で空席を確認します。</li><li>必要であればキャンセル待ちを登録します。</li><li>高リスク予約金の要否を判定します。</li><li>トランザクション内で同日周辺の予約をロックし、空席を再確認します。</li><li>予約を登録し、編集トークンと詳細URLを返します。</li></ol><p>予約金が必要な場合はチェックアウトURLを返します。予約金が不要な場合は予約確認通知を送信します。</p><h3 id="空席判定" tabindex="-1">空席判定 <a class="header-anchor" href="#空席判定" aria-label="Permalink to &quot;空席判定&quot;">​</a></h3><p>空席判定は <code>api/lib/reservation-availability.php</code> に集約されています。</p><p>判定対象は次の通りです。</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>営業時間</td><td><code>open_time</code>, <code>close_time</code>, <code>last_order_offset_min</code></td></tr><tr><td>定休日</td><td><code>weekly_closed_days</code></td></tr><tr><td>リードタイム</td><td><code>lead_time_hours</code></td></tr><tr><td>最大受付日数</td><td><code>max_advance_days</code></td></tr><tr><td>予約枠間隔</td><td><code>slot_interval_min</code></td></tr><tr><td>滞在時間</td><td><code>default_duration_min</code></td></tr><tr><td>人数範囲</td><td><code>min_party_size</code>, <code>max_party_size</code></td></tr><tr><td>前後バッファ</td><td><code>buffer_before_min</code>, <code>buffer_after_min</code></td></tr><tr><td>Web予約ルール</td><td><code>web_phone_only_min_party_size</code>, ピーク時間の組数・人数上限、席エリアフィルタ</td></tr><tr><td>既存予約</td><td><code>cancelled</code>, <code>no_show</code> 以外の有効予約</td></tr><tr><td>仮押さえ</td><td>キャンセル待ち通知時に作成される <code>reservation_holds</code></td></tr><tr><td>席割当</td><td>1卓、2卓結合、3卓結合の順で割当可能か確認</td></tr></tbody></table><p>顧客向けWeb予約では、設定により大人数を電話のみへ誘導できます。ピーク時間帯は、Web予約の組数・人数上限を別途設定できます。</p><h3 id="店舗側予約api" tabindex="-1">店舗側予約API <a class="header-anchor" href="#店舗側予約api" aria-label="Permalink to &quot;店舗側予約API&quot;">​</a></h3><p><code>api/store/reservations.php</code> はスタッフ以上の認証と店舗アクセス権を確認します。</p><p>GET の主な用途は次の通りです。</p><table tabindex="0"><thead><tr><th>用途</th><th>内容</th></tr></thead><tbody><tr><td>日別一覧</td><td>指定日の予約、待ち候補、席、設定サマリーを返す</td></tr><tr><td>詳細取得</td><td>予約詳細、変更履歴、通知履歴を返す</td></tr><tr><td>空席確認</td><td>スタッフ向けの空席候補を返す</td></tr></tbody></table><p>POST は店舗側の予約作成です。<code>web</code>, <code>phone</code>, <code>walk_in</code>, <code>google</code>, <code>external</code>, <code>ai_chat</code> の source を受け付けます。ステータスには <code>waitlisted</code> も指定できます。</p><p>PATCH は、顧客情報、人数、日時、滞在時間、メモ、タグ、コース、席、ステータス、来店フォロー状態、キャンセル待ち呼び出し状態を更新できます。変更内容は予約履歴に記録されます。</p><p>DELETE は予約を <code>cancelled</code> に更新し、キャンセル理由、履歴、必要に応じた通知、顧客キャンセル回数、キャンセル待ち通知処理を行います。</p><h3 id="予約ステータス" tabindex="-1">予約ステータス <a class="header-anchor" href="#予約ステータス" aria-label="Permalink to &quot;予約ステータス&quot;">​</a></h3><p>主に使う予約ステータスは次の通りです。</p><ul><li><code>pending</code></li><li><code>confirmed</code></li><li><code>seated</code></li><li><code>no_show</code></li><li><code>cancelled</code></li><li><code>completed</code></li><li><code>waitlisted</code></li></ul><p>no-show 確定は <code>api/store/reservation-no-show.php</code> で処理します。対象は <code>confirmed</code> または <code>pending</code> の予約です。予約金の与信がある場合は、設定と決済状態に応じて捕捉処理が呼ばれます。</p><h3 id="変更履歴" tabindex="-1">変更履歴 <a class="header-anchor" href="#変更履歴" aria-label="Permalink to &quot;変更履歴&quot;">​</a></h3><p>予約履歴は <code>api/lib/reservation-history.php</code> を通じて記録されます。店舗側の詳細取得では <code>change_history</code> として返されます。</p><p>実装上、主に次の変更が履歴化されます。</p><ul><li>顧客名、電話番号、メール</li><li>人数</li><li>予約日時</li><li>滞在時間</li><li>メモ</li><li>タグ</li><li>コース</li><li>割り当て席</li><li>ステータス</li><li>来店フォロー状態</li><li>キャンセル待ち呼び出し状態</li></ul><p>「誰が」「いつ」「何を」「変更前」「変更後」を確認できる前提でUIに渡しています。</p><h3 id="リスク判定" tabindex="-1">リスク判定 <a class="header-anchor" href="#リスク判定" aria-label="Permalink to &quot;リスク判定&quot;">​</a></h3><p>店舗側一覧では、予約ごとに運用リスクが付与されます。判定は <code>api/store/reservations.php</code> 内の予約シリアライズ処理で行われます。</p><p>主なリスクは次の通りです。</p><table tabindex="0"><thead><tr><th>リスク</th><th>内容</th></tr></thead><tbody><tr><td>遅刻</td><td>予約時刻から5分以上経過で警告、15分以上で強い警告</td></tr><tr><td>no-show履歴</td><td>no-show回数がある顧客</td></tr><tr><td>キャンセル多発</td><td>キャンセル回数が多い顧客</td></tr><tr><td>ブラックリスト</td><td>顧客情報でブラックリスト扱い</td></tr><tr><td>大人数</td><td>8名以上の予約</td></tr></tbody></table><p>対応候補として、電話確認、店長確認、来店フォロー、予約金検討などが返されます。</p><h3 id="予約金" tabindex="-1">予約金 <a class="header-anchor" href="#予約金" aria-label="Permalink to &quot;予約金&quot;">​</a></h3><p>予約金処理は <code>api/lib/reservation-deposit.php</code> と予約作成APIから利用されます。</p><p>通常の予約金は、予約設定の <code>deposit_enabled</code>, <code>deposit_per_person</code>, <code>deposit_min_party_size</code> を使います。高リスク予約金は <code>high_risk_deposit_enabled</code> が有効な場合に、no-show回数、大人数、ブラックリスト近似などをもとに判定されます。</p><p>店舗側で作成する予約では、運用上必要な場合に予約金をスキップする指定ができます。</p><h3 id="リマインド通知と再送" tabindex="-1">リマインド通知と再送 <a class="header-anchor" href="#リマインド通知と再送" aria-label="Permalink to &quot;リマインド通知と再送&quot;">​</a></h3><p>予約通知は <code>api/lib/reservation-notifier.php</code> が担当します。</p><p>対応している通知タイプには、予約確認、24時間前リマインド、2時間前リマインド、キャンセル、no-show、予約金関連があります。</p><p>通知経路は次の通りです。</p><table tabindex="0"><thead><tr><th>経路</th><th>実装条件</th></tr></thead><tbody><tr><td>メール</td><td><code>posla_send_mail</code> で送信し、<code>reservation_notifications_log</code> に記録</td></tr><tr><td>LINE</td><td>テナントLINE設定が有効で、対象通知タイプが有効、顧客LINE紐付けがある場合</td></tr><tr><td>SMS Webhook</td><td><code>reservation_settings.sms_enabled=1</code>、HTTPSのWebhook URL、顧客電話番号がある場合</td></tr></tbody></table><p>自動リマインドは <code>api/cron/reservation-reminders.php</code> で処理します。</p><table tabindex="0"><thead><tr><th>リマインド</th><th>対象</th></tr></thead><tbody><tr><td>24時間前</td><td>現在時刻の23〜25時間後の予約</td></tr><tr><td>2時間前</td><td>現在時刻の90〜150分後の予約</td></tr></tbody></table><p>失敗したリマインドは、<code>reminder_retry_minutes</code> と <code>reminder_retry_max</code> に従って再送対象になります。上限に達したものは店長確認対象として扱われます。</p><p>cron をHTTPで実行する場合は <code>X-POSLA-CRON-SECRET</code> ヘッダーと <code>POSLA_CRON_SECRET</code> の一致が必要です。CLI実行も許可されています。</p><h3 id="キャンセル待ちと仮押さえ" tabindex="-1">キャンセル待ちと仮押さえ <a class="header-anchor" href="#キャンセル待ちと仮押さえ" aria-label="Permalink to &quot;キャンセル待ちと仮押さえ&quot;">​</a></h3><p>キャンセル待ちは <code>api/lib/reservation-waitlist.php</code> が担当します。</p><p>満席時に <code>join_waitlist</code> が指定されると、条件に応じて待ち候補を登録します。キャンセルや no-show で空席が出た場合、候補の中から条件に合う1件に空席案内を送ります。</p><p>空席案内時には <code>reservation_holds</code> に仮押さえを作成します。保持時間は <code>waitlist_lock_minutes</code> で、最小5分、最大120分に丸められます。</p><p>現在の空席案内通知は、顧客メールアドレスがある候補に対するメール送信です。LINEやSMSでのキャンセル待ち空席案内は、この処理では実装されていません。</p><h3 id="顧客向け予約変更・キャンセル" tabindex="-1">顧客向け予約変更・キャンセル <a class="header-anchor" href="#顧客向け予約変更・キャンセル" aria-label="Permalink to &quot;顧客向け予約変更・キャンセル&quot;">​</a></h3><p><code>public/customer/js/reserve-detail-app.js</code> と顧客向けAPIにより、予約詳細ページから内容確認、予約金支払い、日時・人数・メモ変更、キャンセルができます。</p><p><code>api/customer/reservation-update.php</code> は、予約IDと編集トークンを検証します。<code>cancelled</code>, <code>seated</code>, <code>no_show</code>, <code>completed</code> の予約は変更できません。キャンセル期限を過ぎた予約も変更できません。変更時は空席を再確認し、問題がなければ履歴を記録します。</p><h3 id="ハンディ・kds・レジへの予約文脈連携" tabindex="-1">ハンディ・KDS・レジへの予約文脈連携 <a class="header-anchor" href="#ハンディ・kds・レジへの予約文脈連携" aria-label="Permalink to &quot;ハンディ・KDS・レジへの予約文脈連携&quot;">​</a></h3><p>予約から着席した卓では、<code>table_sessions.reservation_id</code> を起点に予約情報と <code>reservation_customers</code> の常連情報を各業務画面へ渡します。</p><table tabindex="0"><thead><tr><th>画面</th><th>表示内容</th></tr></thead><tbody><tr><td>ハンディ</td><td>テーブルカード、注意バッジ、予約一覧に予約者名、人数、予約時刻、メモ、好み、アレルギー、注意点、来店回数、VIP、リスク、通知未対応を表示</td></tr><tr><td>KDS</td><td>注文カードに予約者名、人数、予約時刻、コース、メモ、好み、注意点、来店回数を表示。アレルギーは「予約アレルギー」として強調</td></tr><tr><td>POSレジ</td><td>テーブル一覧と会計詳細に予約者名、人数、予約時刻、コース、メモ、好み、アレルギー、注意点、来店回数を表示</td></tr></tbody></table><p>KDS API <code>api/kds/orders.php</code> は、予約系テーブルが未適用の環境でも落ちないよう、カラム・テーブル存在確認を行い、存在する場合だけ <code>reservation_context</code> をレスポンスに含めます。</p><h2 id="社内確認時の注意" tabindex="-1">社内確認時の注意 <a class="header-anchor" href="#社内確認時の注意" aria-label="Permalink to &quot;社内確認時の注意&quot;">​</a></h2><h3 id="実装済みとして書いてよいこと" tabindex="-1">実装済みとして書いてよいこと <a class="header-anchor" href="#実装済みとして書いてよいこと" aria-label="Permalink to &quot;実装済みとして書いてよいこと&quot;">​</a></h3><ul><li>テイクアウトの時間枠上限、品数上限、ピーク上限</li><li>テイクアウトオンライン決済返金成功後の運用ステータス <code>refunded</code> 反映</li><li>テイクアウトの梱包チェック、SLA警告、到着連絡、準備完了LINE通知</li><li>予約のWeb予約枠ルール、ピーク制御、大人数電話誘導</li><li>予約の変更履歴、リマインド自動送信、失敗再送、店長確認対象化</li><li>予約の高リスク予約金判定</li><li>予約のキャンセル待ち仮押さえ</li><li>予約通知のメール、LINE、SMS Webhook</li><li>ハンディ・KDS・POSレジでの予約文脈、常連情報、アレルギー、注意点表示</li></ul><h3 id="実装済みとして書いてはいけないこと" tabindex="-1">実装済みとして書いてはいけないこと <a class="header-anchor" href="#実装済みとして書いてはいけないこと" aria-label="Permalink to &quot;実装済みとして書いてはいけないこと&quot;">​</a></h3><ul><li>テイクアウトSMS通知</li><li>テイクアウトの現金払いWeb注文</li><li>予約ボードのリアルタイムWebSocket更新</li><li>キャンセル待ち空席案内のLINE/SMS自動送信</li><li>POSLA画面上だけでオンライン決済返金が完了するという説明</li></ul><h3 id="デプロイ時の確認" tabindex="-1">デプロイ時の確認 <a class="header-anchor" href="#デプロイ時の確認" aria-label="Permalink to &quot;デプロイ時の確認&quot;">​</a></h3><p>新規環境へ反映する場合は、既存の <code>schema.sql</code> を直接編集せず、該当マイグレーションが適用済みか確認してください。</p><p>特に確認するマイグレーションは次の通りです。</p><ul><li><code>sql/migration-p1-61-reservation-arrival-followups.sql</code></li><li><code>sql/migration-p1-62-reservation-waitlist-calls.sql</code></li><li><code>sql/migration-p1-63-reservation-operational-safety.sql</code></li><li><code>sql/migration-p1-64-reservation-autonomy.sql</code></li><li><code>sql/migration-p1-65-takeout-operations.sql</code></li><li><code>sql/migration-p1-66-takeout-customer-convenience.sql</code></li></ul>',118)])])}const b=t(r,[["render",c]]);export{u as __pageData,b as default};
